import{_ as e,o as a,c as r,a0 as o}from"./chunks/framework.jwovEGr5.js";const w=JSON.parse('{"title":"软路由配置","description":"","frontmatter":{"title":"软路由配置","date":"2020-08-26T13:47:32.000Z","category":"Home","tags":["Home"]},"headers":[],"relativePath":"posts/ruan-lu-you-pei-zhi.md","filePath":"posts/ruan-lu-you-pei-zhi.md","lastUpdated":1783006593000}'),p={name:"posts/ruan-lu-you-pei-zhi.md"};function i(l,t,n,h,s,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="_0x10-什么是软路由" tabindex="-1">0x10 什么是软路由 <a class="header-anchor" href="#_0x10-什么是软路由" aria-label="Permalink to &quot;0x10 什么是软路由&quot;">​</a></h1><p>软路由是指利用台式机或服务器配合软件形成路由解决方案，主要靠软件的设置，达成路由器的功能；而硬路由则是以特有的硬设备，包括处理器、电源供应、嵌入式软件，提供设定的路由器功能。</p><p>一般软路由都是x86架构，而硬路由基本都是MIPS/ARM等架构。也有软路由系统厂商出的一些非x86架构的软路由，比如Mikrotik。</p><p>所以软路由可以用老PC机、工控机来做，如果有条件也可以买专业的软路由，虽然也基本都是多网口的工控机。</p><h1 id="_0x20-为什么需要软路由" tabindex="-1">0x20 为什么需要软路由 <a class="header-anchor" href="#_0x20-为什么需要软路由" aria-label="Permalink to &quot;0x20 为什么需要软路由&quot;">​</a></h1><p>大部分童鞋家里都有硬路由，甚至几千块的高端路由，但很多情况下，硬路由并不能满足需求，还是需要软路由</p><p>如果家里带宽超过500M，建议用软路由，低端硬路由跑不满。 如果家里有多条宽带要做合并，建议用软路由。 如果用高速梯子，建议用软路由。 如果终端设备比较多，有个几十上百，建议用软路由。 如果需要各种杂七杂八的插件，建议用软路由。 如果需要路由之外更多功能，建议用软路由。 如果需要做QoS等各种网络限制，建议用软路由。</p><p>当然，相比硬路由，软路由一般成本都比较高，不过也看对比，高端硬路由比低端软路由贵多了。</p><p>如果有淘汰的老机器，比如以前的赛扬、奔腾的老机器，再插块网卡就能当软路由，不过就是功耗大了点，体积大了点。笔记本的话，一般上个usb网卡或者mini pcie转出来的网卡也能用。</p><p>有个视频可以看看： <a href="https://www.youtube.com/watch?v=ilcXa6D6Kjw" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=ilcXa6D6Kjw</a></p><h1 id="_0x30-软路由硬件选型" tabindex="-1">0x30 软路由硬件选型 <a class="header-anchor" href="#_0x30-软路由硬件选型" aria-label="Permalink to &quot;0x30 软路由硬件选型&quot;">​</a></h1><p>看自己的需求，如果就200M带宽，那J1900的软路由就可以，内存有个2G、SSD 16G足够，直接PVE或者裸机LEDE，ROS、爱快、海蜘蛛也行。</p><p>如果500M以上，建议3865U/3965U，可以物理LEDE，但PVE/ESXi更合适。当然，如果上i3/i5/i7的也没问题。或者搞个联想M920X，性能杠杠的，就是价格有点小贵。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E8%BD%AF%E8%B7%AF%E7%94%B1%E9%85%8D%E7%BD%AE/1598425558975.png" alt=""></p><p>网口用intel最佳，螃蟹卡也凑合能用。有2个足够，其他的网口可以用交换机扩展，当然如果4个/6个网口更好，交换机可以省掉。</p><h1 id="_0x40-软路由系统选择" tabindex="-1">0x40 软路由系统选择 <a class="header-anchor" href="#_0x40-软路由系统选择" aria-label="Permalink to &quot;0x40 软路由系统选择&quot;">​</a></h1><p>一般企业用途用ROS、海蜘蛛、爱快都不错。个人用LEDE比较好。 可以直接裸机装，但如果硬件性能不错，还是走ESXi/PVE比较好，个人喜欢ESXi，兼容性好一些，性能也不错，PVE说是轻量级，但很多人对比测试过，不比ESXi强多少，但稳定性和兼容性比ESXi还是差一些。</p><p>有个ESXi和PVE对比： <a href="https://www.youtube.com/watch?v=jbC5iIktONo" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=jbC5iIktONo</a></p><p>LEDE/OpenWRT/爱快/海蜘蛛/ROS等等，在ESXi上都可以自己尝试下，选出最喜欢的，最合适的，虚拟化就是这么任性！</p><p>ROS+LEDE可以参考，讲的非常详细，照做就可以： <a href="https://www.youtube.com/watch?v=mkJxDSMPlPU" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=mkJxDSMPlPU</a><a href="https://www.youtube.com/watch?v=n0aqV8rbKmE" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=n0aqV8rbKmE</a></p><p>LEDE可以尝试lean最新的： <a href="https://github.com/coolsnowwolf/lede" target="_blank" rel="noreferrer">https://github.com/coolsnowwolf/lede</a></p><p>也可以用经典稳定版： <a href="https://github.com/coolsnowwolf/openwrt" target="_blank" rel="noreferrer">https://github.com/coolsnowwolf/openwrt</a></p><p>这里分享2个我编译出来的稳定版openwrt，vmdk格式，有ext4和squashfs两个版本，默认密码password：</p><p><a href="https://wws.lanzous.com/b01bodvyf" target="_blank" rel="noreferrer">https://wws.lanzous.com/b01bodvyf</a> 密码:4mj6</p><h1 id="_0x50-其他" tabindex="-1">0x50 其他 <a class="header-anchor" href="#_0x50-其他" aria-label="Permalink to &quot;0x50 其他&quot;">​</a></h1><p>我原本用3865U，后面换了i5的软路由，运行ESXi 6.7u3，架构可以看另一篇文章<a href="https://blog.white-alone.com/%E5%AE%B6%E5%BA%AD%E4%B8%87%E5%85%86%E5%B1%80%E5%9F%9F%E7%BD%91%E8%AE%B0%E5%BD%95/" target="_blank" rel="noreferrer">《家庭万兆局域网记录》</a></p><p>之所以升级，是打算将更多的虚拟机迁移到软路由上，比如本地Mirror镜像： <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E8%BD%AF%E8%B7%AF%E7%94%B1%E9%85%8D%E7%BD%AE/1598429908256.png" alt=""></p><p>再比如用Gogs搭建的私人代码仓库： <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E8%BD%AF%E8%B7%AF%E7%94%B1%E9%85%8D%E7%BD%AE/1598430225099.png" alt=""></p><p>还有其他的很多轻量级服务，都一并装到软路由上。</p><p>比如可以黑一个群晖、黑一个QNAP、装一个FreeNAS，都可以。</p><p>WiFi就简单很多，直接用wifi6路由当AP即可，不需要其他任何功能。</p><p>如果房子够大，就AC+AP，妥妥的</p>',32)])])}const E=e(p,[["render",i]]);export{w as __pageData,E as default};
